387		trimmed := strings.TrimSpace(string(data))
388		if trimmed == "" || trimmed == "null" {
389			return nil
390		}
391	
392		p.Present = true
393		switch trimmed[0] {
394		case '[':
395			return json.Unmarshal(data, &p.Checks)
396		case '{':
397			var check preClaimReadinessCheck
398			if err := json.Unmarshal(data, &check); err != nil {
399				return err
400			}
401			p.Checks = []preClaimReadinessCheck{check}
402			return nil
403		case '"':
404			var value string
405			if err := json.Unmarshal(data, &value); err != nil {
406				return err
407			}
408			p.Malformed = "readiness_checks must be an object or array"
409			p.Evidence = value
410			return nil
411		default:
412			p.Malformed = "readiness_checks must be an object or array"
413			p.Evidence = trimmed
