806	func decodeReadinessClassificationPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
807		var out preClaimReadinessClassificationPromptResult
808		if err := json.Unmarshal([]byte(payload), &out); err != nil {
809			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness classification result: %w", err)
810		}
811		if out.ReadinessChecks.Malformed != "" {
812			detail := malformedReadinessChecksDetail(out.ReadinessChecks)
813			classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
814			return PreClaimIntakeResult{
815				Outcome:      classified.IntakeOutcome,
816				Reason:       classified.Reason,
817				SystemReason: classified.SystemReason,
818				Detail:       detail,
819			}, nil
820		}
821		reasons := failedReadinessReasons(out.ReadinessChecks.Checks)
822		detail := firstNonEmptyReadinessDetail(out.Rationale, out.Detail, out.Reasoning)
823		classified := ClassifyReadinessWithMode(out.Classification, reasons, detail, qualityMode)
824		if detail == "" {
825			detail = readinessCheckEvidence(out.ReadinessChecks.Checks)
826		}
827		detail = readinessDetailWithReason(classified, detail)
828	
829		rewrite := PreClaimIntakeRewrite{
830			Description:   strings.TrimSpace(out.Rewrite.Description),
831			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
832			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
833		}
834		result := PreClaimIntakeResult{
835			Outcome:             classified.IntakeOutcome,
836			Reason:              classified.Reason,
837			SystemReason:        classified.SystemReason,
838			Detail:              detail,
839			EstimatedDifficulty: normalizeReadinessEstimatedDifficulty(out.Difficulty.EstimatedDifficulty),
840		}
841		if classified.Classification == ReadinessClassificationNeedsRefine && hasPreClaimIntakeRewrite(rewrite) {
842			result.Outcome = PreClaimIntakeActionableButRewritten
843			result.Rewrite = rewrite
844		}
845		return result, nil
846	}
