928	func resolveReadinessEstimatedDifficulty(b *bead.Bead, readinessEstimate string) escalation.EstimatedDifficulty {
929		if difficulty, ok := escalation.BeadEstimatedDifficulty(b); ok {
930			return difficulty
931		}
932		switch normalizeReadinessEstimatedDifficulty(readinessEstimate) {
933		case string(escalation.DifficultyEasy):
934			return escalation.DifficultyEasy
935		case string(escalation.DifficultyHard):
936			return escalation.DifficultyHard
937		default:
938			return escalation.DifficultyMedium
939		}
940	}
