38	// NewPreClaimDecompositionHook dispatches an orchestrator splitter for beads
39	// that readiness classifies as too_large without returning concrete children.
40	// It returns a lossless split proposal; the execute loop owns validation,
41	// child creation, dependency wiring, and fallback behavior.
42	func NewPreClaimDecompositionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) func(context.Context, string) (*PreClaimDecomposition, error) {
43		return func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
44			return runPreClaimDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
45		}
46	}
