48	func runPreClaimDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) (*PreClaimDecomposition, error) {
49		tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
50		defer cancel()
51	
52		b, err := store.Get(ctx, beadID)
53		if err != nil {
54			return nil, fmt.Errorf("decomposer: load bead: %w", err)
55		}
56		prompt, err := buildPreClaimDecomposerPrompt(store, b)
57		if err != nil {
58			return nil, err
59		}
60		runtime := AgentRunRuntime{
61			Prompt:           prompt,
62			PromptSource:     preClaimDecomposerPromptSource,
63			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
64			ClearRoutingPins: true,
65			ClearProfile:     true,
66			ClearMinPower:    true,
67			ClearMaxPower:    true,
68		}
69		result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
70		if err != nil {
71			if tctx.Err() != nil {
72				return nil, tctx.Err()
73			}
74			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, fmt.Sprintf("dispatch error: %s", err.Error())); fallbackErr == nil {
75				return fallback, nil
76			}
77			return nil, fmt.Errorf("decomposer: dispatch: %w", err)
78		}
79		output := strings.TrimSpace(result.CondensedOutput)
80		if output == "" {
81			output = strings.TrimSpace(result.Output)
82		}
83		if output == "" {
84			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, "empty output"); fallbackErr == nil {
85				return fallback, nil
86			}
87			return nil, fmt.Errorf("decomposer: empty output")
88		}
89		decomp, ok := parsePreClaimDecompositionOutput(output)
90		if !ok {
91			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, "invalid output"); fallbackErr == nil {
92				return fallback, nil
93			}
94			return nil, fmt.Errorf("decomposer: invalid output")
95		}
96		if err := validatePreClaimDecomposition(decomp); err != nil {
97			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, err.Error()); fallbackErr == nil {
98				return fallback, nil
99			}
100			return nil, err
101		}
102		return decomp, nil
103	}
