115					Attempted: true,
116					Succeeded: false,
117					Path:      Decompose,
118					CostUSD:   result.CostUSD,
119				}, nil
120			}
121			return &PostLadderExhaustionResult{
122				Attempted: true,
123				Succeeded: true,
124				Path:      Decompose,
125				CostUSD:   result.CostUSD,
126			}, nil
127		}
