37	// NewReframePostLadderExhaustionHook creates a PostLadderExhaustionHook that
38	// dispatches runReframer for SpecGap and PersistentExecutionFailed failure
39	// classes. TooLarge is not handled here; it belongs to the Decompose path.
40	func NewReframePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
41		return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
42			switch failureClass {
43			case SpecGap, PersistentExecutionFailed:
44			default:
45				return &PostLadderExhaustionResult{Attempted: false}, nil
46			}
47			result := runReframer(ctx, store, runner, rcfg, projectRoot, beadID)
48			if result.Failed {
49				return &PostLadderExhaustionResult{
50					Attempted: true,
51					Succeeded: false,
52					Path:      Reframe,
53					CostUSD:   result.CostUSD,
54				}, nil
55			}
56			return &PostLadderExhaustionResult{
57				Attempted: true,
58				Succeeded: true,
59				Path:      Reframe,
60				CostUSD:   result.CostUSD,
61			}, nil
62		}
63	}
