65	// runReframer dispatches a smart+ powerClass agent to rewrite the bead's description
66	// and acceptance criteria after the escalation ladder has been exhausted.
67	// On success, the bead description/AC are updated, the
68	// consecutive_ladder_exhaustions counter is cleared, and a "reframe-applied"
69	// event is emitted. On failure a ReframeResult with Failed=true is returned.
70	func runReframer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) ReframeResult {
71		tctx, cancel := context.WithTimeout(ctx, reframerDefaultTimeout)
72		defer cancel()
73	
74		b, err := store.Get(ctx, beadID)
75		if err != nil {
76			return ReframeResult{Failed: true, Reason: "store_error"}
77		}
78	
79		prompt, err := buildReframerPrompt(store, b)
80		if err != nil {
81			return ReframeResult{Failed: true, Reason: "prompt_error"}
82		}
83	
84		runtime := AgentRunRuntime{
85			Prompt:           prompt,
86			WorkDir:          projectRoot,
87			PromptSource:     reframerPromptSource,
88			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
89			ClearRoutingPins: true,
90			ClearProfile:     true,
91			ClearMinPower:    true,
92			ClearMaxPower:    true,
93		}
94	
95		result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
96		if err != nil && result == nil {
97			if tctx.Err() != nil {
98				return ReframeResult{Failed: true, Reason: "timeout"}
99			}
100			return ReframeResult{Failed: true, Reason: "dispatch_error"}

