629	func worktreeStillLive(meta agent.ExecutionCleanupMetadata, runStates []agent.RunState, now time.Time) bool {
630		if meta.Preserved || meta.ActiveCandidateCycle || strings.TrimSpace(meta.CandidateRef) != "" {
631			return true
632		}
633		if worktreeLivenessAlive(meta.Liveness, now) {
634			return true
635		}
636		for _, state := range runStates {
637			if !runStateMatchesWorktree(state, meta) {
638				continue
639			}
640			if strings.TrimSpace(state.CandidateCyclePhase) != "" || strings.TrimSpace(state.CandidateRef) != "" {
641				return true
642			}
643			if worktreeRunStateAlive(state, now) {
644				return true
645			}
646		}
647		return false
648	}
649	
650	func worktreeLivenessAlive(liveness *agent.ExecutionCleanupLiveness, now time.Time) bool {
651		if liveness == nil {
652			return false
653		}
654		if processAlive(liveness.PID) {
655			return true
656		}
657		if !liveness.ExpiresAt.IsZero() && now.Before(liveness.ExpiresAt) {
658			return true
659		}
660		return !liveness.RefreshedAt.IsZero() && now.Sub(liveness.RefreshedAt) <= 2*time.Minute
661	}
662	
663	func worktreeRunStateAlive(state agent.RunState, now time.Time) bool {
664		if processAlive(state.PID) {
665			return true
666		}
667		if !state.ExpiresAt.IsZero() && now.Before(state.ExpiresAt) {
668			return true
669		}
670		return !state.RefreshedAt.IsZero() && now.Sub(state.RefreshedAt) <= agent.RunStateLivenessTTL
671	}
672	
673	func runStateMatchesWorktree(state agent.RunState, meta agent.ExecutionCleanupMetadata) bool {
674		if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
675			return true
676		}
677		return meta.WorktreePath != "" &&
678			state.WorktreePath != "" &&
679			filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath)
680	}
681	
682	func processAlive(pid int) bool {
683		if pid <= 0 {
684			return false
685		}
686		proc, err := os.FindProcess(pid)
687		if err != nil {
688			return false
689		}
690		return proc.Signal(syscall.Signal(0)) == nil
691	}
